func dedupe<T: Hashable>(_ items: [T]) -> [T] {
    // Track which values we've already emitted.
    var seen = Set<T>()
    // `Set.insert` returns `inserted: false` for duplicates, so the filter
    // keeps only the first occurrence of each value, preserving input order.
    return items.filter { seen.insert($0).inserted }
}
